precision highp float;
uniform float u_time;
uniform vec2 u_resolution;
uniform vec2 u_value_range;
uniform vec3 u_palette[6];
float safediv(float a, float b){ float d = abs(b) > 1e-3 ? b : (b >= 0.0 ? 1e-3 : -1e-3); return a / d; }
float field(float u, float v, float t){ return (cos(((u * 4.0) + (v * 0.0) + t)) + cos(((u * 2.0000000000000004) + (v * 3.4641016151377544) + t)) + cos(((u * (-1.9999999999999991)) + (v * 3.464101615137755) + t)) + cos(((u * (-4.0)) + (v * 4.898587196589413e-16) + t)) + cos(((u * (-2.0000000000000018)) + (v * (-3.464101615137754)) + t)) + cos(((u * 2.0000000000000004) + (v * (-3.4641016151377544)) + t))); }
vec3 ramp(float x){
  x = clamp(x, 0.0, 1.0);
  float s = x * float(6 - 1);
  int idx = int(floor(s));
  float f = fract(s);
  vec3 a = u_palette[0];
  vec3 b = u_palette[0];
  for (int k = 0; k < 6; k++) {
    if (k == idx) a = u_palette[k];
    if (k == idx + 1) b = u_palette[k];
  }
  return mix(a, b, f);
}
void main(){
  vec2 uv = (gl_FragCoord.xy / u_resolution) * 2.0 - 1.0;
  float val = field(uv.x, uv.y, u_time);
  float n = (val - u_value_range.x) / max(1e-6, (u_value_range.y - u_value_range.x));
  gl_FragColor = vec4(ramp(n), 1.0);
}
